114→    // -- Spec-governed primitives (Operation Taxonomy in JJS0) --
115→
116→    /// Resolve Pace — shared read primitive
117→    ///
118→    /// Navigate Gallops from a coronet to the target pace and its current tack state.
119→    /// Returns PaceContext with parsed identities and current state snapshot.
120→    pub fn jjrg_resolve_pace(&self, coronet: &str) -> Result<jjrg_PaceContext, String> {
121→        use crate::jjrf_favor::jjrf_Coronet as Coronet;
122→
123→        let parsed = Coronet::jjrf_parse(coronet)
124→            .map_err(|e| format!("Invalid coronet: {}", e))?;
125→        let coronet_key = parsed.jjrf_display();
126→        let firemark = parsed.jjrf_parent_firemark();
127→        let firemark_key = firemark.jjrf_display();
128→
129→        let heat = self.heats.get(&firemark_key)
130→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
131→        let pace = heat.paces.get(&coronet_key)
132→            .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
133→        let current = pace.tacks.first()
134→            .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
135→
136→        Ok(jjrg_PaceContext {
137→            coronet_key,
138→            firemark_key,
139→            state: current.state.clone(),
140→            text: current.text.clone(),
141→            silks: current.silks.clone(),
142→            direction: current.direction.clone(),
143→        })
144→    }
145→
146→    /// Prepend Tack — shared write primitive
147→    ///
148→    /// Insert a new tack at position zero of a pace's tack history.
149→    /// Takes a PaceContext (from resolve_pace) so the coronet is parsed exactly once.
150→    pub fn jjrg_prepend_tack(&mut self, ctx: &jjrg_PaceContext, tack: jjrg_Tack) -> Result<(), String> {
151→        let heat = self.heats.get_mut(&ctx.firemark_key)
152→            .ok_or_else(|| format!("Heat '{}' not found", ctx.firemark_key))?;
153→        let pace = heat.paces.get_mut(&ctx.coronet_key)
154→            .ok_or_else(|| format!("Pace '{}' not found", ctx.coronet_key))?;
155→
156→        pace.tacks.insert(0, tack);
157→        Ok(())
158→    }
159→
160→    /// Revise Docket — composed method
161→    ///
162→    /// Pure state transform: resolve_pace → update docket → prepend_tack.
163→    /// Takes basis and ts from caller (procedure layer captures I/O).
164→    /// Returns PaceContext so calling procedure has firemark/silks for commit message.
165→    pub fn jjrg_revise_docket(&mut self, coronet: &str, docket: &str, basis: &str, ts: &str) -> Result<jjrg_PaceContext, String> {
166→        if docket.is_empty() {
167→            return Err("docket text must not be empty".to_string());
168→        }
169→
170→        let ctx = self.jjrg_resolve_pace(coronet)?;
171→
172→        let tack = jjrg_Tack {
173→            ts: ts.to_string(),
174→            state: ctx.state.clone(),
175→            text: docket.to_string(),
176→            silks: ctx.silks.clone(),
177→            basis: basis.to_string(),
178→            direction: None,
179→        };
180→
181→        self.jjrg_prepend_tack(&ctx, tack)?;
182→
183→        Ok(ctx)
184→    }
185→}
