192→    /// Build a minimal Gallops from stack immediates — no disk, no git.
193→    /// Keys use display format (with ₣/₢ prefixes) matching real Gallops structure.
194→    fn make_test_gallops(state: jjrg_PaceState, text: &str, silks: &str) -> jjrg_Gallops {
195→        let firemark_key = "₣AA".to_string();
196→        let coronet_key = "₢AAAAA".to_string();
197→        let tack = jjrg_Tack {
198→            ts: "20260318T120000Z".to_string(),
199→            state,
200→            text: text.to_string(),
201→            silks: silks.to_string(),
202→            basis: "0000000".to_string(),
203→            direction: None,
204→        };
205→        let pace = jjrg_Pace {
206→            tacks: vec![tack],
207→        };
208→        let mut paces = BTreeMap::new();
209→        paces.insert(coronet_key.clone(), pace);
210→        let heat = jjrg_Heat {
211→            silks: "test-heat".to_string(),
212→            creation_time: "260318".to_string(),
213→            status: jjrg_HeatStatus::Racing,
214→            order: vec![coronet_key],
215→            next_pace_seed: "AAB".to_string(),
216→            next_pensum_seed: "AA".to_string(),
217→            paddock_file: ".claude/jjm/jjp_test.md".to_string(),
218→            paces,
219→        };
220→        let mut heats = BTreeMap::new();
221→        heats.insert(firemark_key.clone(), heat);
222→        jjrg_Gallops {
223→            schema_version: Some(4),
224→            next_heat_seed: "AB".to_string(),
225→            heat_order: vec![firemark_key],
226→            heats,
227→        }
228→    }
229→
230→    #[test]
231→    fn test_resolve_pace_returns_context() {
232→        let gallops = make_test_gallops(jjrg_PaceState::Rough, "original docket", "test-pace");
233→        let ctx = gallops.jjrg_resolve_pace("AAAAA").unwrap();
234→        assert_eq!(ctx.firemark_key, "₣AA");
235→        assert_eq!(ctx.coronet_key, "₢AAAAA");
236→        assert_eq!(ctx.state, jjrg_PaceState::Rough);
237→        assert_eq!(ctx.text, "original docket");
238→        assert_eq!(ctx.silks, "test-pace");
239→        assert_eq!(ctx.direction, None);
240→    }
241→
242→    #[test]
243→    fn test_revise_docket_updates_text() {
244→        let mut gallops = make_test_gallops(jjrg_PaceState::Rough, "original docket", "test-pace");
245→        let ctx = gallops.jjrg_revise_docket("AAAAA", "updated docket", "abc1234", "20260318T130000Z").unwrap();
246→
247→        // Context returns pre-mutation state
248→        assert_eq!(ctx.text, "original docket");
249→
250→        // Gallops now has new tack prepended with caller-provided basis+ts
251→        let pace = gallops.heats["₣AA"].paces.get("₢AAAAA").unwrap();
252→        assert_eq!(pace.tacks.len(), 2);
253→        assert_eq!(pace.tacks[0].text, "updated docket");
254→        assert_eq!(pace.tacks[0].state, jjrg_PaceState::Rough);
255→        assert_eq!(pace.tacks[0].basis, "abc1234");
256→        assert_eq!(pace.tacks[0].ts, "20260318T130000Z");
257→        assert_eq!(pace.tacks[1].text, "original docket");
258→    }
259→
260→    #[test]
261→    fn test_revise_docket_empty_text_rejected() {
262→        let mut gallops = make_test_gallops(jjrg_PaceState::Rough, "original", "test-pace");
263→        let result = gallops.jjrg_revise_docket("AAAAA", "", "abc1234", "20260318T130000Z");
264→        assert!(result.is_err());
265→        assert!(result.unwrap_err().contains("must not be empty"));
266→    }
