386→// jjx_send — synchronous exec via legatio
387→// ============================================================================
388→
389→pub struct jjrlg_SendArgs {
390→    pub legatio: String,
391→    pub command: String,
392→}
393→
394→/// Execute a command synchronously on the fundus via a legatio.
395→///
396→/// The command string is interpreted by `bash -c` on the fundus after
397→/// `cd RELDIR`. Returns 0 with remote exit code in output on SSH success;
398→/// returns 1 on SSH transport failure.
399→pub fn jjrlg_run_send(args: jjrlg_SendArgs, officium_id: &str) -> (i32, String) {

400→    let cn = JJRLG_CMD_NAME_SEND;
401→    let mut output = vvco_Output::buffer();
402→
403→    let officium_dir = zjjrlg_officium_dir(officium_id);
404→    let state = match zjjrlg_load_legatio(&officium_dir, &args.legatio) {
405→        Ok(s) => s,
406→        Err(e) => {
407→            vvco_err!(output, "{}: {}", cn, e);
408→            return (1, output.vvco_finish());
409→        }
410→    };
411→
412→    let remote_cmd = format!(
413→        "cd \"$HOME/{}\" && bash -c {}",
414→        state.reldir,
415→        zjjrlg_shell_quote(&args.command)
416→    );
417→
418→    let result = match zjjrlg_ssh_exec(&state.host, &state.user, &remote_cmd) {
419→        Ok(r) => r,
420→        Err(e) => {
421→            vvco_err!(output, "{}: SSH failed: {}", cn, e);
422→            return (1, output.vvco_finish());
423→        }
424→    };
425→
426→    let stdout = String::from_utf8_lossy(&result.stdout);
427→    let stderr = String::from_utf8_lossy(&result.stderr);
428→
429→    if !stdout.is_empty() {
430→        vvco_out!(output, "{}", stdout);
431→    }
432→    if !stderr.is_empty() {
433→        vvco_err!(output, "{}", stderr);
434→    }
435→    vvco_out!(output, "Exit: {}", result.exit_code);
436→
437→    // Return 0 — SSH transport succeeded. Remote exit code is in the output.
438→    (0, output.vvco_finish())
439→}
