443→// ============================================================================
444→
445→pub struct jjrlg_PlantArgs {
446→    pub legatio: String,
447→    pub commit: String,
448→}
449→
450→/// Reset the fundus workspace to an exact git commit.
451→///
452→/// Runs `git fetch origin && git reset --hard <commit> && git clean -dxf`
453→/// over SSH. Fail-fast on any step.
454→pub fn jjrlg_run_plant(args: jjrlg_PlantArgs, officium_id: &str) -> (i32, String) {
455→    let cn = JJRLG_CMD_NAME_PLANT;
456→    let mut output = vvco_Output::buffer();
457→
458→    // Validate git ref contains only safe characters
459→    if let Err(e) = zjjrlg_validate_git_ref(&args.commit) {
460→        vvco_err!(output, "{}: {}", cn, e);
461→        return (1, output.vvco_finish());
462→    }
463→
464→    let officium_dir = zjjrlg_officium_dir(officium_id);
465→    let state = match zjjrlg_load_legatio(&officium_dir, &args.legatio) {
466→        Ok(s) => s,
467→        Err(e) => {
468→            vvco_err!(output, "{}: {}", cn, e);
469→            return (1, output.vvco_finish());
470→        }
471→    };
472→
473→    let plant_script = format!(
474→        concat!(
475→            "cd \"$HOME/{reldir}\" || exit 1\n",
476→            "git fetch origin || exit 2\n",
477→            "git reset --hard {commit} || exit 3\n",
478→            "git clean -dxf || exit 4\n",
479→            "echo \"PLANT_OK:$(git rev-parse HEAD)\""
480→        ),
481→        reldir = state.reldir,
482→        commit = args.commit
483→    );
484→
485→    vvco_out!(output, "Planting {} on {}@{}:~/{} ...",
486→        args.commit, state.user, state.host, state.reldir);
487→
488→    let result = match zjjrlg_ssh_exec(&state.host, &state.user, &plant_script) {
489→        Ok(r) => r,
490→        Err(e) => {
491→            vvco_err!(output, "{}: SSH failed: {}", cn, e);
492→            return (1, output.vvco_finish());
493→        }
494→    };
495→
496→    let stdout = String::from_utf8_lossy(&result.stdout);
497→    let stderr = String::from_utf8_lossy(&result.stderr);
498→
499→    if result.exit_code != 0 {

500→        vvco_err!(output, "{}: failed (exit {})", cn, result.exit_code);
501→        if !stdout.trim().is_empty() { vvco_err!(output, "{}", stdout.trim()); }
502→        if !stderr.trim().is_empty() { vvco_err!(output, "{}", stderr.trim()); }
503→        return (1, output.vvco_finish());
504→    }
505→
506→    if let Some(line) = stdout.lines().find(|l| l.starts_with("PLANT_OK:")) {
507→        vvco_out!(output, "Plant succeeded. HEAD now at {}", &line["PLANT_OK:".len()..]);
508→    } else {
509→        vvco_out!(output, "Plant succeeded.");
510→    }
511→
512→    (0, output.vvco_finish())
513→}
