587→// ============================================================================
588→// Tabtarget validation
589→// ============================================================================
590→
591→/// Validate a tabtarget is a safe bare filename in tt/.
592→fn zjjrlg_validate_tabtarget(s: &str) -> Result<(), String> {
593→    if s.is_empty() {
594→        return Err("tabtarget must not be empty".to_string());
595→    }
596→    if s.contains('/') || s.contains("..") {
597→        return Err("tabtarget must be a bare filename (no path components)".to_string());
598→    }
599→    if !s.ends_with(".sh") {

700→
701→    let z_branch = vvc::vvce_git_command(&["rev-parse", "--abbrev-ref", "HEAD"])
702→        .output()
703→        .map_err(|e| format!("git rev-parse --abbrev-ref failed: {}", e))?;
704→    let z_branch_name = String::from_utf8_lossy(&z_branch.stdout).trim().to_string();
705→
706→    let z_remote_ref = format!("origin/{}", z_branch_name);
707→    let z_remote = vvc::vvce_git_command(&["rev-parse", &z_remote_ref])
708→        .output()
709→        .map_err(|e| format!("git rev-parse {} failed: {}", z_remote_ref, e))?;
710→    let z_remote_sha = String::from_utf8_lossy(&z_remote.stdout).trim().to_string();
711→
712→    if z_head_sha != z_remote_sha {
713→        return Err(format!(
714→            "curia HEAD {} is not pushed to {} (remote {}). Push before dispatching.",
715→            &z_head_sha[..z_abbrev_len.min(z_head_sha.len())],
716→            z_remote_ref,
717→            &z_remote_sha[..z_abbrev_len.min(z_remote_sha.len())]
718→        ));
719→    }
720→
721→    Ok(())
722→}
723→
724→/// Launch an async dispatch on the fundus via nohup.
725→///
726→/// Mints a pensum token, launches the tabtarget via nohup wrapper over SSH,
727→/// reads initial burx.env to capture BURX_TEMP_DIR, persists pensum state.
728→pub fn jjrlg_run_relay(args: jjrlg_RelayArgs, officium_id: &str) -> (i32, String) {
729→    let cn = JJRLG_CMD_NAME_RELAY;
730→    let mut output = vvco_Output::buffer();
731→
732→    // Curia readiness gate: clean tree + pushed HEAD
733→    if let Err(e) = zjjrlg_require_curia_ready() {
734→        vvco_err!(output, "{}: relay refused: {}", cn, e);
735→        return (1, output.vvco_finish());
736→    }
737→
738→    if let Err(e) = zjjrlg_validate_tabtarget(&args.tabtarget) {
739→        vvco_err!(output, "{}: {}", cn, e);
740→        return (1, output.vvco_finish());
741→    }
742→
743→    let officium_dir = zjjrlg_officium_dir(officium_id);
744→    if !officium_dir.is_dir() {
745→        vvco_err!(output, "{}: officium directory not found", cn);
746→        return (1, output.vvco_finish());
747→    }
748→
749→    // Load legatio state
750→    let state = match zjjrlg_load_legatio(&officium_dir, &args.legatio) {
751→        Ok(s) => s,
752→        Err(e) => {
753→            vvco_err!(output, "{}: {}", cn, e);
754→            return (1, output.vvco_finish());
755→        }
756→    };
757→
758→    // Mint pensum: lock → load → mint → persist → release
759→    let pensum = match zjjrlg_mint_pensum_locked(&args.firemark) {
760→        Ok(p) => p,
761→        Err(e) => {
762→            vvco_err!(output, "{}: {}", cn, e);
763→            return (1, output.vvco_finish());
764→        }
765→    };
766→    let pensum_token = pensum.jjrf_as_str().to_string();
767→    let pensum_display = pensum.jjrf_display();
768→
769→    vvco_out!(output, "Relaying {} via {} ({})", args.tabtarget, args.legatio, pensum_display);
770→
771→    // SSH #1: Launch nohup wrapper on fundus
772→    let nohup_script = zjjrlg_build_nohup_script(
773→        &state.reldir, &pensum_token, args.timeout, &args.tabtarget,
774→    );
775→
776→    let launch = match zjjrlg_ssh_exec(&state.host, &state.user, &nohup_script) {
777→        Ok(r) => r,
778→        Err(e) => {
779→            vvco_err!(output, "{}: SSH launch failed: {}", cn, e);
780→            return (1, output.vvco_finish());
781→        }
782→    };
783→
784→    let launch_stdout = String::from_utf8_lossy(&launch.stdout);
785→    if launch.exit_code != 0 || !launch_stdout.contains("RELAY_OK") {
786→        let stderr = String::from_utf8_lossy(&launch.stderr);
787→        vvco_err!(output, "{}: nohup launch failed (exit {})", cn, launch.exit_code);
788→        if !stderr.trim().is_empty() { vvco_err!(output, "  {}", stderr.trim()); }
789→        return (1, output.vvco_finish());
790→    }
791→
792→    vvco_out!(output, "Dispatch launched on fundus.");
793→
794→    // SSH #2: Read initial burx.env — poll with label matching to avoid stale reads
795→    let burx_script = format!("\
796→cd \"$HOME/{}\" || exit 1
797→z_retries=0
798→while [ $z_retries -lt {} ]; do
799→  if [ -f '{}/current/burx.env' ]; then

800→    z_label=$(grep '^BURX_LABEL=' '{}/current/burx.env' 2>/dev/null | head -1 | cut -d= -f2)
801→    if [ \"$z_label\" = '{}' ]; then
802→      cat '{}/current/burx.env'
803→      exit 0
804→    fi
805→  fi
806→  sleep {}
807→  z_retries=$((z_retries + 1))
808→done
809→exit 1",
810→        state.reldir,
811→        BURX_INITIAL_POLL_MAX_RETRIES,
812→        state.output_root_dir, state.output_root_dir, pensum_token,
813→        state.output_root_dir,
814→        BURX_INITIAL_POLL_DELAY_SECS,
815→    );
816→
817→    let burx = match zjjrlg_ssh_exec(&state.host, &state.user, &burx_script) {
818→        Ok(r) => r,
819→        Err(e) => {
820→            vvco_err!(output, "{}: SSH burx read failed: {}", cn, e);
821→            return (1, output.vvco_finish());
822→        }
823→    };
824→
825→    if burx.exit_code != 0 {
826→        vvco_err!(output, "{}: burx.env with matching label not found after {} retries",
827→            cn, BURX_INITIAL_POLL_MAX_RETRIES);
828→        return (1, output.vvco_finish());
829→    }
830→
831→    let burx_content = String::from_utf8_lossy(&burx.stdout);
832→    let burx_fields = zjjrlg_parse_burx(&burx_content);
833→
834→    let temp_dir = match burx_fields.get("BURX_TEMP_DIR") {
835→        Some(d) if !d.is_empty() => d.clone(),
836→        _ => {
837→            vvco_err!(output, "{}: BURX_TEMP_DIR not found in burx.env", cn);
838→            return (1, output.vvco_finish());
839→        }
840→    };
841→
842→    let pid = match burx_fields.get("BURX_PID") {
843→        Some(p) if !p.is_empty() => p.clone(),
844→        _ => {
845→            vvco_err!(output, "{}: BURX_PID not found in burx.env", cn);
846→            return (1, output.vvco_finish());
847→        }
848→    };
849→
850→    let began_at = burx_fields.get("BURX_BEGAN_AT").cloned().unwrap_or_default();
851→
852→    // Persist pensum state
853→    let pensum_state = jjrlg_PensumState {
854→        legatio: args.legatio.clone(),
855→        firemark: args.firemark.clone(),
856→        temp_dir: temp_dir.clone(),
857→        pid,
858→        tabtarget: args.tabtarget.clone(),
859→        timeout: args.timeout,
860→        began_at,
861→    };
862→
863→    if let Err(e) = zjjrlg_save_pensum(&officium_dir, &pensum_token, &pensum_state) {
864→        vvco_err!(output, "{}: {}", cn, e);
865→        return (1, output.vvco_finish());
866→    }
867→
868→    vvco_out!(output, "Pensum {} active.", pensum_display);
869→    vvco_out!(output, "Remote temp dir: {}", temp_dir);
870→
871→    (0, output.vvco_finish())
872→}
873→
874→// ============================================================================
875→// Pensum probe (shared by jjx_check)
876→// ============================================================================
877→
878→/// Result of a single pensum probe via SSH.
879→struct zjjrlg_ProbeResult {
880→    report: String,
881→    burx_fields: HashMap<String, String>,
882→    files: Vec<String>,
883→}
884→
885→/// Execute a single probe of a pensum's status via SSH.
886→///
887→/// Reads burx.env from the pensum's durable temp dir, checks for
888→/// BURX_EXIT_STATUS (terminal), probes PID via kill -0, and lists
889→/// files on terminal status.
890→fn zjjrlg_probe_pensum(
891→    legatio_state: &jjrlg_LegatioState,
892→    pensum_state: &jjrlg_PensumState,
893→) -> Result<zjjrlg_ProbeResult, String> {
894→    let probe_script = format!("\
895→if [ ! -f '{temp_dir}/burx.env' ]; then
896→  echo 'JJRLG_REPORT:lost'
897→  exit 0
898→fi
899→cat '{temp_dir}/burx.env'

900→echo 'JJRLG_BURX_END'
901→z_es=$(grep '^BURX_EXIT_STATUS=' '{temp_dir}/burx.env' 2>/dev/null | head -1 | cut -d= -f2)
902→if [ -n \"$z_es\" ]; then
903→  echo 'JJRLG_REPORT:stopped'
904→  echo 'JJRLG_FILES_BEGIN'
905→  ls -1 '{temp_dir}/'
906→  echo 'JJRLG_FILES_END'
907→else
908→  if kill -0 {pid} 2>/dev/null; then
909→    echo 'JJRLG_REPORT:running'
910→  else
911→    echo 'JJRLG_REPORT:orphaned'
912→  fi
913→fi",
914→        temp_dir = pensum_state.temp_dir,
915→        pid = pensum_state.pid,
916→    );
917→
918→    let result = zjjrlg_ssh_exec(
919→        &legatio_state.host,
920→        &legatio_state.user,
921→        &probe_script,
922→    ).map_err(|e| format!("SSH probe failed: {}", e))?;
923→
924→    let stdout = String::from_utf8_lossy(&result.stdout);
925→
926→    // Parse report line
927→    let report = stdout.lines()
928→        .find(|l| l.starts_with("JJRLG_REPORT:"))
929→        .map(|l| l["JJRLG_REPORT:".len()..].to_string())
930→        .unwrap_or_else(|| "unknown".to_string());
931→
932→    // Parse BURX fields (lines before JJRLG_BURX_END, excluding sentinel lines)
933→    let burx_content: String = stdout.lines()
934→        .take_while(|l| !l.starts_with("JJRLG_BURX_END"))
935→        .filter(|l| !l.starts_with("JJRLG_"))
936→        .collect::<Vec<_>>()
937→        .join("\n");
938→    let burx_fields = zjjrlg_parse_burx(&burx_content);
939→
940→    // Parse file list (between JJRLG_FILES_BEGIN and JJRLG_FILES_END)
941→    let mut in_files = false;
942→    let mut files = Vec::new();
943→    for line in stdout.lines() {
944→        if line == "JJRLG_FILES_BEGIN" {
945→            in_files = true;
946→            continue;
947→        }
948→        if line == "JJRLG_FILES_END" {
949→            break;
950→        }
951→        if in_files && !line.is_empty() {
952→            files.push(line.to_string());
953→        }
954→    }
955→
956→    Ok(zjjrlg_ProbeResult { report, burx_fields, files })
957→}
958→
959→/// Format probe result into output buffer.
960→fn zjjrlg_format_probe_output(pensum_display: &str, probe: &zjjrlg_ProbeResult, output: &mut vvco_Output) {
961→    vvco_out!(output, "Pensum: {}", pensum_display);
962→    vvco_out!(output, "Report: {}", probe.report);
963→
964→    for key in &["BURX_PID", "BURX_BEGAN_AT", "BURX_TABTARGET", "BURX_TEMP_DIR",
965→                  "BURX_TRANSCRIPT", "BURX_LOG_HIST", "BURX_LABEL",
966→                  "BURX_EXIT_STATUS", "BURX_ENDED_AT"] {
967→        if let Some(val) = probe.burx_fields.get(*key) {
968→            if !val.is_empty() {
969→                vvco_out!(output, "{}: {}", key, val);
970→            }
971→        }
972→    }
973→
974→    if !probe.files.is_empty() {
975→        vvco_out!(output, "Files:");
976→        for f in &probe.files {
977→            vvco_out!(output, "  {}", f);
978→        }
979→    }
980→}
