982→// ============================================================================
983→// jjx_check — probe or poll pensum status
984→// ============================================================================
985→
986→pub struct jjrlg_CheckArgs {
987→    pub pensum: String,
988→    pub timeout: u64,
989→}
990→
991→/// Probe or poll a pensum's status on the fundus.
992→///
993→/// timeout=0: instant probe (single SSH round-trip).
994→/// timeout>0: poll until terminal state or timeout expires.
995→///
996→/// Returns BURX fields + liveness report (running/orphaned/stopped/lost).
